BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?attr ?attrName WHERE {
  ?signal vocab:NamedElement_name "offloadSensorOffsets%20Cmd" .
  ?signal vocab:Signal_ownedAttribute ?attr .
  OPTIONAL { ?attr vocab:NamedElement_name ?attrName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name WHERE {
  ?pkg vocab:NamedElement_name "M1CS%20Requirements" .
  ?pkg vocab:Element_ownedElement+ ?elem .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?childName ?childType WHERE {
  ?elem vocab:NamedElement_name "M1CS%20Actuator%20Range%20of%20Travel%20Budget" .
  ?elem vocab:Element_ownedElement+ ?child .
  OPTIONAL { ?child vocab:NamedElement_name ?childName }
  OPTIONAL { ?child rdf:type ?childType }
}
LIMIT 25
